// Extrai dados do payload da Evolution API v2
const payload = $json;

let numero = "";
let mensagem = "";
let nome_contato = "";
let tipo_mensagem = "texto";

try {
  // Extrai número do remetente
  if (payload.data?.key?.remoteJid) {
    numero = payload.data.key.remoteJid;
  } else if (payload.key?.remoteJid) {
    numero = payload.key.remoteJid;
  } else if (payload.from) {
    numero = payload.from;
  }

  // Extrai nome do contato
  if (payload.data?.pushName) {
    nome_contato = payload.data.pushName;
  } else if (payload.pushName) {
    nome_contato = payload.pushName;
  } else if (payload.data?.verifiedBizName) {
    nome_contato = payload.data.verifiedBizName;
  } else {
    nome_contato = "Desconhecido";
  }

  // Extrai mensagem conforme o tipo
  const messageData = payload.data?.message || payload.message || {};

  if (messageData.conversation) {
    mensagem = messageData.conversation;
    tipo_mensagem = "texto";
  } else if (messageData.extendedTextMessage?.text) {
    mensagem = messageData.extendedTextMessage.text;
    tipo_mensagem = "texto";
  } else if (messageData.imageMessage?.caption) {
    mensagem = messageData.imageMessage.caption || "[Imagem]";
    tipo_mensagem = "imagem";
  } else if (messageData.videoMessage?.caption) {
    mensagem = messageData.videoMessage.caption || "[Vídeo]";
    tipo_mensagem = "video";
  } else if (messageData.audioMessage) {
    mensagem = "[Áudio]";
    tipo_mensagem = "audio";
  } else if (messageData.documentMessage?.fileName) {
    mensagem = `[Documento: ${messageData.documentMessage.fileName}]`;
    tipo_mensagem = "documento";
  } else {
    mensagem = "mensagem_vazia";
  }

  // Limpa o número (remove espaços e caracteres especiais desnecessários)
  numero = String(numero).trim();

  console.log('✅ Dados extraídos:', { numero, mensagem, nome_contato, tipo_mensagem });

} catch (error) {
  console.error('❌ Erro ao processar payload:', error);
  mensagem = mensagem || "erro_processamento";
  nome_contato = nome_contato || "Desconhecido";
}

return {
  numero: numero,
  mensagem: mensagem,
  nome_contato: nome_contato,
  origem: "whatsapp",
  tipo_mensagem: tipo_mensagem
};
